import React from 'react';
import { useAuth } from '../../contexts/AuthContext';
import './Quiz.css';

const Quiz = () => {
  const { user } = useAuth();

  return (
    <div className="quiz-container">
      <div className="container">
        <h1>Career Assessment Quiz</h1>
        <p>Discover your ideal career path with our intelligent quiz.</p>
        
        {user ? (
          <div className="quiz-info">
            <div className="info-card">
              <h3>How it works:</h3>
              <ul>
                <li>Answer questions about your interests and skills</li>
                <li>Get personalized career recommendations</li>
                <li>Receive course suggestions from top platforms</li>
                <li>Track your progress over time</li>
              </ul>
              <button className="btn btn-primary">Start Quiz (Coming Soon)</button>
            </div>
          </div>
        ) : (
          <div className="auth-required">
            <p>Please log in to take the career assessment quiz.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Quiz;
